import{_ as e,o as r,c as t,ag as i}from"./chunks/framework.C9sp7nFj.js";const b=JSON.parse('{"title":"第一次出国完整流程","description":"从护照办理到出发回国的完整出国流程指南","frontmatter":{"title":"第一次出国完整流程","description":"从护照办理到出发回国的完整出国流程指南"},"headers":[],"relativePath":"beginners/first-time-abroad.md","filePath":"beginners/first-time-abroad.md","lastUpdated":null}'),o={name:"beginners/first-time-abroad.md"};function n(l,a,h,d,s,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="第一次出国完整流程" tabindex="-1">第一次出国完整流程 <a class="header-anchor" href="#第一次出国完整流程" aria-label="Permalink to &quot;第一次出国完整流程&quot;">​</a></h1><h2 id="第一步-办理护照" tabindex="-1">第一步：办理护照 <a class="header-anchor" href="#第一步-办理护照" aria-label="Permalink to &quot;第一步：办理护照&quot;">​</a></h2><p>前往户籍所在地出入境管理局办理，通常需要 7-15 个工作日。</p><h2 id="第二步-申请签证" tabindex="-1">第二步：申请签证 <a class="header-anchor" href="#第二步-申请签证" aria-label="Permalink to &quot;第二步：申请签证&quot;">​</a></h2><p>根据目的地国家要求申请相应类型的签证，准备所需材料。</p><h2 id="第三步-预订机票" tabindex="-1">第三步：预订机票 <a class="header-anchor" href="#第三步-预订机票" aria-label="Permalink to &quot;第三步：预订机票&quot;">​</a></h2><p>使用比价网站找到性价比高的航班，注意行李额度。</p><h2 id="第四步-预订住宿" tabindex="-1">第四步：预订住宿 <a class="header-anchor" href="#第四步-预订住宿" aria-label="Permalink to &quot;第四步：预订住宿&quot;">​</a></h2><p>根据预算选择酒店、民宿或青旅，注意位置和评价。</p><h2 id="第五步-行前准备" tabindex="-1">第五步：行前准备 <a class="header-anchor" href="#第五步-行前准备" aria-label="Permalink to &quot;第五步：行前准备&quot;">​</a></h2><p>打包行李、购买保险、兑换货币、下载离线地图。</p><h2 id="第六步-出发当天" tabindex="-1">第六步：出发当天 <a class="header-anchor" href="#第六步-出发当天" aria-label="Permalink to &quot;第六步：出发当天&quot;">​</a></h2><p>提前到达机场，办理值机和托运，通过安检和边检。</p><h2 id="第七步-抵达后" tabindex="-1">第七步：抵达后 <a class="header-anchor" href="#第七步-抵达后" aria-label="Permalink to &quot;第七步：抵达后&quot;">​</a></h2><p>入境检查、提取行李、连接网络、前往住宿地。</p><h2 id="第八步-回国" tabindex="-1">第八步：回国 <a class="header-anchor" href="#第八步-回国" aria-label="Permalink to &quot;第八步：回国&quot;">​</a></h2><p>确认航班时间，预留充足时间前往机场，办理退税（如有）。</p>',17)])])}const u=e(o,[["render",n]])